var uDivs = Math.Max(1, GetInt(parameters, "uDivisions", 8));
var vDivs = Math.Max(1, GetInt(parameters, "vDivisions", 8));
var barWidth = GetFloat(parameters, "barWidth", 0.3f);
var barShape = GetChoice(parameters, "barShape", "square");
var colorA = GetColor(parameters, "colorA", Colors.White);
var colorB = GetColor(parameters, "colorB", Colors.Black);
var rotation = GetFloat(parameters, "rotationAngle", 0f);
var offset = GetFloat(parameters, "offset", 0f);
var softness = GetFloat(parameters, "softness", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var aR = colorA.R / 255f; var aG = colorA.G / 255f; var aB = colorA.B / 255f;
var bR = colorB.R / 255f; var bG = colorB.G / 255f; var bB = colorB.B / 255f;
var rotRad = rotation * MathF.PI / 180f;
var cosR = MathF.Cos(rotRad);
var sinR = MathF.Sin(rotRad);

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Rotate UV
    var ru = u * cosR - v * sinR;
    var rv = u * sinR + v * cosR;

    // Grid cell coordinates
    var cellU = ru * uDivs;
    var cellV = rv * vDivs;
    var localU = cellU - MathF.Floor(cellU);
    var localV = cellV - MathF.Floor(cellV);

    // Distance to nearest bar edge
    var distU = barShape switch
    {
        "round" => MathF.Abs(localU - 0.5f) * 2f,
        "diamond" => (MathF.Abs(localU - 0.5f) + MathF.Abs(localV - 0.5f)),
        _ => MathF.Max(MathF.Abs(localU - 0.5f), MathF.Abs(localV - 0.5f))
    };

    var threshold = 1f - barWidth;
    var t = (distU - threshold) / Math.Max(softness * 0.1f + 0.001f, 0.001f);
    t = Math.Clamp(t, 0f, 1f);

    if (invert) t = 1f - t;

    var r = Lerp(aR, bR, t);
    var g = Lerp(aG, bG, t);
    var b = Lerp(aB, bB, t);

    buffer.SetPixel(x, y, r, g, b, 1f);
});

return buffer;
}
